mapper.select:
select folder_id, company_id, parent_folder_id, name, sort_order, status, created_by, created_at, updated_at
from document_folders
where folder_id = #{folderId,jdbcType=VARCHAR}

select count(1)
from document_folders
where company_id = #{companyId,jdbcType=VARCHAR}
  and parent_folder_id = #{parentFolderId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ACTIVE'
